// ─── HELPERS ─────────────────────────────────────────────────────────────────
const fmtDate = (str) => { if (!str) return ""; const [y,m,d]=str.split("-"); return `${d}/${m}/${y}`; };
const today = () => new Date().toISOString().split("T")[0];
const addDays = (str, n) => { const d=new Date(str); d.setDate(d.getDate()+n); return d.toISOString().split("T")[0]; };
const getDays = (debut, fin) => {
  const days=[]; let cur=new Date(debut); const end=new Date(fin);
  while(cur<=end){ days.push(cur.toISOString().split("T")[0]); cur.setDate(cur.getDate()+1); }
  return days;
};
const getDayLabel = (str) => new Date(str).toLocaleDateString("fr-FR",{weekday:"short",day:"numeric",month:"short"});
const getDayLabelLong = (str) => new Date(str).toLocaleDateString("fr-FR",{weekday:"long",day:"numeric",month:"long",year:"numeric"});
const getTaux = (s) => {
  if (!s?.stagiaires?.length) return 0;
  const days=getDays(s.dateDebut,s.dateFin), total=days.length*2*(s.stagiaires||[]).length;
  let signed=0; days.forEach(d=>{ const e=s.emargements?.[d]||{matin:[],apmidi:[]}; signed+=e.matin.length+e.apmidi.length; });
  return total===0?0:Math.round(signed/total*100);
};
const isToday  = (s) => { const t=today(); return s.dateDebut<=t&&t<=s.dateFin; };
const isPast   = (s) => new Date(s.dateFin)<new Date();
const isFuture = (s) => new Date(s.dateDebut)>new Date();
const genCode  = (prenom, nom, sessionId) => `${(prenom||'?')[0]}${(nom||'?')[0]}${sessionId}`.toUpperCase();
