// Normalise une session pour garantir que toutes les propriétés existent
const normalizeSession = (s) => ({
  ...s,
  stagiaires:   Array.isArray(s.stagiaires)   ? s.stagiaires   : [],
  emargements:  s.emargements  || {},
  signatures:   s.signatures   || {},
  documents:    Array.isArray(s.documents)    ? s.documents    : [],
  rappels:      Array.isArray(s.rappels)      ? s.rappels      : [],
});

const buildEm = (debut, fin) => {
  const em={}; getDays(debut,fin).forEach(d=>{ em[d]={matin:[],apmidi:[]}; }); return em;
};

