    y+=5;
    doc.text(`à Saint-Péray, le ${getDayLabelLong(day)}`,M,y);

    // Encadré DEVENIR INGESON bas droite
    const bx=W-M-52, by=y-8, bw=52, bh=24;
    doc.setDrawColor(20,20,22); doc.setLineWidth(0.4);
    doc.rect(bx,by,bw,bh);
    doc.setFillColor(20,20,22); doc.rect(bx,by,bw,7,"F");
