// ─── SIGNATURE PAD ────────────────────────────────────────────────────────────
const SignaturePad = ({onSign,signed}) => {
  const canvasRef=useRef(null);
  const [isDrawing,setIsDrawing]=useState(false);
  const [hasStrokes,setHasStrokes]=useState(false);
  const getPos=(e,canvas)=>{
    const rect=canvas.getBoundingClientRect(), src=e.touches?e.touches[0]:e;
    return {x:(src.clientX-rect.left)*(canvas.width/rect.width),y:(src.clientY-rect.top)*(canvas.height/rect.height)};
  };
  const startDraw=(e)=>{e.preventDefault();const c=canvasRef.current;if(!c)return;const p=getPos(e,c);c.getContext("2d").beginPath();c.getContext("2d").moveTo(p.x,p.y);setIsDrawing(true);setHasStrokes(true);};
  const draw=(e)=>{e.preventDefault();if(!isDrawing)return;const c=canvasRef.current;if(!c)return;const ctx=c.getContext("2d"),p=getPos(e,c);ctx.lineWidth=2.5;ctx.lineCap="round";ctx.lineJoin="round";ctx.strokeStyle="#E8B84B";ctx.lineTo(p.x,p.y);ctx.stroke();ctx.beginPath();ctx.moveTo(p.x,p.y);};
  const stopDraw=(e)=>{e.preventDefault();setIsDrawing(false);};
  const clear=()=>{const c=canvasRef.current;if(!c)return;c.getContext("2d").clearRect(0,0,c.width,c.height);setHasStrokes(false);};
  const validate=()=>{if(!hasStrokes)return;onSign(canvasRef.current.toDataURL("image/png"));};
  if(signed) return <div style={{background:"#D1FAE5",borderRadius:12,padding:"16px",textAlign:"center",border:"1.5px solid #065F46"}}><Icon name="checkCircle" color="#059669" size={28}/><p style={{margin:"8px 0 0",color:"#065F46",fontWeight:700,fontSize:14}}>Émargement signé ✓</p></div>;
  return (
    <div style={{border:"2px dashed #454549",borderRadius:12,overflow:"hidden",background:"#1C1C1E"}}>
      <div style={{position:"relative"}}>
        {!hasStrokes&&<div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",pointerEvents:"none",color:"#555555",fontSize:13}}>✍️ Dessinez votre signature ici</div>}
        <canvas ref={canvasRef} width={680} height={200} style={{display:"block",width:"100%",height:100,touchAction:"none",cursor:"crosshair"}}
          onMouseDown={startDraw} onMouseMove={draw} onMouseUp={stopDraw} onMouseLeave={stopDraw}
          onTouchStart={startDraw} onTouchMove={draw} onTouchEnd={stopDraw}/>
      </div>
      <div style={{display:"flex",gap:8,padding:"8px 12px",background:"#2A2A2E",borderTop:"1px solid #3A3A3E"}}>
        <button onClick={clear} style={{flex:1,background:"#242428",border:"none",borderRadius:8,padding:"10px",fontSize:13,color:"#888888",cursor:"pointer",fontWeight:600}}>Effacer</button>
        <button onClick={validate} style={{flex:2,background:hasStrokes?"#1E3A5F":"#666666",border:"none",borderRadius:8,padding:"10px",fontSize:13,color:"#fff",cursor:hasStrokes?"pointer":"not-allowed",fontWeight:700}}>✓ Valider la signature</button>
      </div>
    </div>
  );
};

