        <button onClick={()=>setShowNewSession(true)} style={{background:"#E8B84B",border:"none",borderRadius:12,padding:"10px 14px",display:"flex",alignItems:"center",gap:6,cursor:"pointer",color:"#fff",fontSize:13,fontWeight:700}}>
          <Icon name="plus" size={16} color="#fff"/> Nouvelle
        </button>
